exemplos.python:
valores_brutos = []
print("Registre os valores (digite 'fim' para encerrar):")

while True:
    entrada = input("Valor: ")
    if entrada == "fim":
        break
    valores_brutos.append(float(entrada))

total_valido = 0
erros = 0
for v in valores_brutos:
    if v >= 0:
        total_valido += v
    else:
        erros += 1

print(f"Total apurado: R$ {total_valido:.2f}")
print(f"Registros inválidos descartados: {erros}")

pacotes = []

while True:
    codigo = input("Código do pacote (ou 'encerrar'): ")
    if codigo == "encerrar":
        break
    pacotes.append(int(codigo))

urgente_enviado = False
for p in pacotes:
    if p == 999:
        urgente_enviado = True
        break

if urgente_enviado:
    print("Pacote 999 foi despachado.")
else:
    print("ALERTA: pacote 999 ficou no armazém.")

vendas = []

while True:
    v = float(input("Venda (0 para encerrar): "))
    if v == 0:
        break
    vendas.append(v)

total_pequenas = 0.0
qtd_grandes = 0
for v in vendas:
    if v <= 20:
        total_pequenas += v
    else:
        qtd_grandes += 1

print(f"Total em vendas pequenas: R$ {total_pequenas:.2f}")
print(f"Vendas grandes (> 20): {qtd_grandes}")
